import { Component, h, Prop, Element, Listen, Event, EventEmitter } from '@stencil/core';
import { KEYBOARD_KEYS } from '../../models/keycodes.model';
import { getColorClass, getLabelClass, containerBaseClass } from './wdpr-bottom-nav.utils';

@Component({
  tag: 'wdpr-bottom-nav-item',
  shadow: true,
})
export class WdprBottomNavItem {
  @Element() el: HTMLWdprBottomNavItemElement;

  @Prop() label!: string;
  @Prop() mediaType?: 'icon' | 'avatar' = 'icon';
  @Prop() mediaSize?: 'small' | 'medium' | 'large' = 'medium';
  @Prop() iconName?: string;
  @Prop() iconBackground?: 'circle' | 'square' | 'none' = 'none';
  @Prop() iconVariant?: 'primary' | 'secondary' = 'secondary';
  @Prop() customLabelClass?: string = '';
  @Prop() imageUrl?: string;

  @Prop({ reflect: true }) disabled?: boolean = false;
  @Prop({ reflect: true }) selected?: boolean = false;

  @Event({ eventName: 'itemSelected' }) itemSelected: EventEmitter<boolean>;

  @Listen('keydown')
  handleKeyDown(ev: KeyboardEvent) {
    if (ev.key == KEYBOARD_KEYS.ENTER || ev.key == KEYBOARD_KEYS.SPACE) {
      ev.preventDefault();
      this._itemClick();
    }

    if (ev.key == KEYBOARD_KEYS.ESCAPE) {
      ev.preventDefault();
      (document.activeElement as HTMLElement)?.blur();
    }
  }

  private get _labelClass(): string {
    return getLabelClass(this._colorClass, this.customLabelClass);
  }

  private get _colorClass(): string {
    return getColorClass(this.disabled);
  }

  private _itemClick() {
    if (this.disabled) return;

    this.selected = !this.selected;
    this.itemSelected.emit(this.selected);
  }

  render() {
    return (
      <div
        class={containerBaseClass}
        tabIndex={this.disabled ? -1 : 0}
        role="button"
        aria-pressed={this.selected ? 'true' : 'false'}
        aria-disabled={this.disabled ? 'true' : undefined}
        onClick={this._itemClick.bind(this)}
      >
        {this.mediaType == 'avatar' && this.imageUrl && (
          <span class="w-400 h-400 mr-025">
            <wdpr-avatar
              imageSrc={this.imageUrl}
              size={this.mediaSize}
              isInteractive={false}
            />
          </span>
        )}

        {this.mediaType == 'icon' && this.iconBackground === 'none' && (
          <span class={this._colorClass + ' p-075'}>
            <wdpr-icon-library
              size={this.mediaSize}
              icon={this.iconName}
              decorative
            />
          </span>
        )}

        {this.mediaType == 'icon' && this.iconBackground !== 'none' && (
          <wdpr-icon
            size={this.mediaSize}
            icon={this.iconName}
            customClass={this._colorClass}
            decorative
            background={this.iconBackground}
            variant={this.iconVariant}
          />
        )}

        <span class={this._labelClass}>
          {this.label}
        </span>
      </div>
    );
  }
}
